<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Conway's Game of Life</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body {
    background: #1a1a2e;
    color: #eee;
    font-family: 'Segoe UI', system-ui, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
    user-select: none;
    -webkit-user-select: none;
  }
  h1 {
    font-size: 1.6rem;
    margin-bottom: 8px;
    color: #e94560;
    letter-spacing: 2px;
  }
  .controls {
    display: flex;
    gap: 10px;
    margin-bottom: 12px;
  }
  button {
    padding: 8px 18px;
    border: none;
    border-radius: 6px;
    font-size: 0.95rem;
    cursor: pointer;
    transition: transform .1s, background .2s;
    color: #fff;
    font-weight: 600;
  }
  button:hover { transform: scale(1.05); }
  button:active { transform: scale(.97); }
  #step { background: #e94560; }
  #play { background: #0f3460; border: 2px solid #e94560; }
  #random { background: #16213e; border: 2px solid #533483; }
  #clear { background: #533483; }
  .info {
    font-size: 0.8rem;
    color: #aaa;
    margin-bottom: 6px;
  }
  canvas#life {
    border: 2px solid #e94560;
    border-radius: 4px;
    cursor: crosshair;
    image-rendering: pixelated;
  }
</style>
</head>
<body>

<h1>GAME OF LIFE</h1>
<div class="controls">
  <button id="step">Step</button>
  <button id="play">Play</button>
  <button id="random">Random</button>
  <button id="clear">Clear</button>
</div>
<div class="info" id="info">Generation: 0 &nbsp;|&nbsp; Cells: 0</div>
<canvas id="life"></canvas>

<script>
(function() {
  'use strict';

  // --- Configuration ---
  const W = 60, H = 60;          // grid dimensions (>=40 each)
  const CELL = 7;                // px per cell → canvas ≈ 420×420 CSS px
  const CANVAS = document.getElementById('life');

  // --- State ---
  let grid = [];                 // W × H array of 0/1
  let gen = 0;
  let playing = false;
  let intervalId = null;
  let dragging = false;

  // --- Init grid ---
  function makeGrid() {
    grid = new Array(H);
    for (let y = 0; y < H; y++) {
      grid[y] = new Uint8Array(W).fill(0);
    }
  }
  makeGrid();

  // --- API: get(x, y) → 0 or 1 (out-of-bounds returns 0) ---
  window.life = {
    w: W, h: H,
    get: function(x, y) {
      if (x < 0 || x >= W || y < 0 || y >= H) return 0;
      return grid[y][x];
    },
    set: function(x, y, v) {
      if (x < 0 || x >= W || y < 0 || y >= H) return;
      grid[y][x] = !!v ? 1 : 0;
    },
    step: function() {
      gen++;
      const next = new Uint8Array(W);
      for (let y = 0; y < H; y++) {
        for (let x = 0; x < W; x++) {
          let n = 0;
          // count neighbours (edges are dead — no wrap)
          for (let dy = -1; dy <= 1; dy++) {
            for (let dx = -1; dx <= 1; dx++) {
              if (dx === 0 && dy === 0) continue;
              const nx = x + dx, ny = y + dy;
              if (nx >= 0 && nx < W && ny >= 0 && ny < H) {
                n += grid[ny][nx];
              }
            }
          }
          // B3/S23
          const alive = grid[y][x];
          next[x] = (alive === 1 && (n === 2 || n === 3)) || (alive === 0 && n === 3) ? 1 : 0;
        }
      }
      // swap grids simultaneously
      const tmp = grid;
      grid = next;
      grid = tmp;
      updateInfo();
      draw();
    },
    clear: function() {
      gen = 0;
      makeGrid();
      updateInfo();
      draw();
    }
  };

  // --- Rendering ---
  function draw() {
    const ctx = CANVAS.getContext('2d');
    CANVAS.width = W * CELL;
    CANVAS.height = H * CELL;
    ctx.clearRect(0, 0, CANVAS.width, CANVAS.height);

    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        if (grid[y][x]) {
          const px = x * CELL, py = y * CELL;
          ctx.fillStyle = '#e94560';
          ctx.fillRect(px + 1, py + 1, CELL - 2, CELL - 2);
          // subtle glow
          ctx.shadowColor = '#e94560';
          ctx.shadowBlur = 3;
          ctx.fillRect(px + 1, py + 1, CELL - 2, CELL - 2);
          ctx.shadowBlur = 0;
        } else {
          // faint grid lines for dead cells
          ctx.strokeStyle = '#2a2a4a';
          ctx.lineWidth = 0.5;
          ctx.strokeRect(px, py, CELL, CELL);
        }
      }
    }

    CANVAS.style.width = W * CELL + 'px';
    CANVAS.style.height = H * CELL + 'px';
  }

  function updateInfo() {
    let count = 0;
    for (let y = 0; y < H; y++) for (let x = 0; x < W; x++) if (grid[y][x]) count++;
    document.getElementById('info').textContent = 'Generation: ' + gen + ' &nbsp;|&nbsp; Cells: ' + count;
  }

  // --- Interaction ---
  CANVAS.addEventListener('mousedown', function(e) {
    dragging = true;
    toggleCellAt(e);
  });
  document.addEventListener('mousemove', function(e) {
    if (dragging) toggleCellAt(e);
  });
  document.addEventListener('mouseup', function() { dragging = false; });

  // Touch support
  CANVAS.addEventListener('touchstart', function(e) {
    e.preventDefault();
    const t = e.touches[0];
    const rect = CANVAS.getBoundingClientRect();
    const x = Math.floor(((t.clientX - rect.left) / rect.width) * W);
    const y = Math.floor(((t.clientY - rect.top) / rect.height) * H);
    toggleCellAt({ clientX: t.clientX, clientY: t.clientY });
  }, { passive: false });

  function toggleCellAt(e) {
    const rect = CANVAS.getBoundingClientRect();
    const x = Math.floor(((e.clientX - rect.left) / rect.width) * W);
    const y = Math.floor(((e.clientY - rect.top) / rect.height) * H);
    window.life.set(x, y, !window.life.get(x, y));
  }

  // --- Buttons ---
  document.getElementById('step').addEventListener('click', function() {
    if (playing) stopPlay();
    window.life.step();
  });

  document.getElementById('play').addEventListener('click', function() {
    if (playing) stopPlay(); else startPlay();
  });

  document.getElementById('random').addEventListener('click', function() {
    for (let y = 0; y < H; y++)
      for (let x = 0; x < W; x++)
        grid[y][x] = Math.random() < 0.25 ? 1 : 0;
    gen = 0;
    updateInfo();
    draw();
  });

  document.getElementById('clear').addEventListener('click', function() {
    window.life.clear();
  });

  // --- Auto-play ---
  function startPlay() {
    playing = true;
    intervalId = setInterval(function() {
      if (!playing) return;
      window.life.step();
    }, 120);
  }
  function stopPlay() {
    playing = false;
    clearInterval(intervalId);
    intervalId = null;
  }

  // --- Initial draw ---
  draw();
})();
</script>
</body>
</html>
